output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?region ?regionLabel WHERE {
  VALUES ?region {
    wd:Q970 wd:Q971 wd:Q972
  }
  ?region rdfs:label ?regionLabel .
  FILTER(LANG(?regionLabel) = "en")
}

